const m = $json.message || {};
return [{ json: {
  chat_id: String(m.chat?.id || ''),
  text: m.text || '',
  has_voice: !!m.voice,
  voice_file_id: m.voice?.file_id || null,
  has_photo: !!m.photo,
  photo_file_id: m.photo ? m.photo[m.photo.length - 1].file_id : null,
  tg_name: [m.chat?.first_name, m.chat?.last_name].filter(Boolean).join(' ')
}}];

const user = $json;
const msg = $('Message Type').first()?.json?.text ? $('Message Type').first().json : $('Merge Transcript').first().json;
const prompt = `Classify the user message into exactly one intent.
Intents: PROFILE_INFO, STATUS_QUERY, DOC_QUESTION, CONSENT_YES, OTP_REPLY, SMALLTALK.
Rules: a 4-8 digit number alone => OTP_REPLY. 'haan'/'yes'/'ok'/'ha' => CONSENT_YES. Mentions of self/family/income/age/job/marital status => PROFILE_INFO. Asking about application progress => STATUS_QUERY.
Reply with JSON only: {"intent": "..."}
Message: ${msg.text}`;
return [{ json: { user_id: user.id, language: user.language, profile: user.profile, chat_id: msg.chat_id, text: msg.text, body: { contents: [{ parts: [{ text: prompt }] }], generationConfig: { responseMimeType: 'application/json', maxOutputTokens: 50 } } } }];

const ctx = $('Build Classifier Request').first().json;
let intent = 'SMALLTALK';
try {
  const raw = $json.candidates?.[0]?.content?.parts?.[0]?.text || '';
  intent = JSON.parse(raw.replace(/```json|```/g, '').trim()).intent || 'SMALLTALK';
} catch (e) { /* default SMALLTALK */ }
return [{ json: { ...ctx, intent } }];

const t = $json.text;
const prompt = `Extract profile fields from this message. Output ONLY JSON with any of: { name, age, gender (male|female|other), marital_status (married|widowed|single|divorced), annual_income (number, INR), category (GEN|OBC|SC|ST), district, state (2-letter code, e.g. RJ), occupation }. Use null for absent fields, never guess income. Message: ${t}`;
return [{ json: { ...$json, body: { contents: [{ parts: [{ text: prompt }] }], generationConfig: { responseMimeType: 'application/json', maxOutputTokens: 200 } } } }];

const ctx = $('Build Field Extract').first().json;
let fields = {};
try {
  const raw = $json.candidates?.[0]?.content?.parts?.[0]?.text || '';
  fields = JSON.parse(raw.replace(/```json|```/g, '').trim());
} catch (e) {}
const clean = Object.fromEntries(Object.entries(fields).filter(([, v]) => v !== null && v !== undefined && v !== ''));
return [{ json: { user_id: ctx.user_id, chat_id: ctx.chat_id, fields: clean } }];

const ctx = $('Parse Intent').first().json;
const apps = items.map(i => i.json);
if (!apps.length || !apps[0].id) return [{ json: { chat_id: ctx.chat_id, reply: 'Aapka abhi koi aavedan nahi hai. Apne baare mein bataiye ya rashan card ki photo bhejiye.' } }];
const lines = [];
for (const a of apps) {
  lines.push(`\u{1F4C4} ${a.scheme_hi || a.scheme_en} \u2014 ${a.state}${a.app_number ? ' (#' + a.app_number + ')' : ''}`);
  for (const [i, e] of (a.timeline || []).entries()) {
    const d = new Date(e.at).toLocaleDateString('en-IN', { day: 'numeric', month: 'short' });
    lines.push(`  ${i + 1}. ${d} \u2014 ${e.payload?.to || e.kind}`);
  }
}
return [{ json: { chat_id: ctx.chat_id, reply: lines.join('\n') } }];
